import { FormDialog } from "@/components/common/dialogs/FormDialog";
import { useEffect, useMemo, useState } from "react";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { SubmitHandler, useForm } from "react-hook-form";
import { Input } from "@/components/ui/input";
import { zodResolver } from "@hookform/resolvers/zod";
import { CreateJobPayload } from "../types/jobs.types";
import { createJobSchema } from "../schemas/create-job.schema";
import { useJobActions } from "../hooks/useJobsActions";
import { useCountries } from "@/shared/hooks/useCountries";
import {
  Select,
  SelectGroup,
  SelectItem,
  SelectContent,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { DynamicSelect } from "@/components/common/DynamicSelect";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";

interface CreateJobFormDialogProps {
  onSuccess: () => void;
  open: boolean;
  setOpen: (open: boolean) => void;
}

interface JobEmploymentTypeOption {
  label: string;
  value: CreateJobPayload["employmentType"];
}

interface JobExperienceLevelOption {
  label: string;
  value: CreateJobPayload["experienceLevel"];
}

interface JobStatusOption {
  label: string;
  value: 'draft' | 'published';
}

export function CreateJobFormDialog({
  onSuccess,
  open = false,
  setOpen,
}: CreateJobFormDialogProps) {
  const { create, loading, apiError, clearApiError } = useJobActions();
  const { countries, loading: countriesLoading } = useCountries();

  const resolver = useMemo(() => zodResolver(createJobSchema), []);

  const form = useForm<CreateJobPayload>({
    resolver,
    defaultValues: {
      title: "",
      description: "",
      country: "",
      city: "",
      employmentType: "full-time",
      experienceLevel: "junior",
      status: "draft",
      salaryMin: undefined,
      salaryMax: undefined,
      isRemote: false,
      department: "",
    },
  });

  const JobEmploymentTypeOptions: JobEmploymentTypeOption[] = [
    { label: "Full-time", value: "full-time" },
    { label: "Part-time", value: "part-time" },
    { label: "Contract", value: "contract" },
    { label: "Internship", value: "internship" },
  ];

  const JobExperienceLevelOptions: JobExperienceLevelOption[] = [
    { label: "Junior", value: "junior" },
    { label: "Mid", value: "mid" },
    { label: "Senior", value: "senior" },
    { label: "Lead", value: "lead" },
  ];

  const JobStatusOptions: JobStatusOption[] = [
    { label: "Draft", value: "draft" },
    { label: "Published", value: "published" },
  ];

  const handleSubmit: SubmitHandler<CreateJobPayload> = async (values) => {
    clearApiError();
    try {
      await create(values);
      form.reset();
      onSuccess();
    } catch {
      //errors handled via useJobActions/useApiError
    }
  };

  const handleClose = () => {
    form.reset();
    clearApiError();
    setOpen(false);
  };

  useEffect(() => {
    if (apiError?.validationErrors) {
      apiError.validationErrors.forEach((error) => {
        form.setError(error.field as keyof CreateJobPayload, {
          type: "server",
          message: error.errors[0],
        });
      });
    } else {
      form.clearErrors();
    }
  }, [apiError?.validationErrors, form]);

  return (
    <FormDialog
      title="Create Department"
      isOpen={open}
      onClose={handleClose}
      onSubmit={handleSubmit}
      loading={loading}
      formId="createJobForm"
    >
      <Form {...form}>
        <form
          id="createJobForm"
          onSubmit={form.handleSubmit(handleSubmit)}
          className="space-y-6 mt-3 mb-2"
        >
          <div className="space-y-5">
            <div className="grid sm:grid-cols-2">
              <FormField
                control={form.control}
                name="title"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Title</FormLabel>
                    <FormControl>
                      <Input placeholder="e.g. Marketing" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="department"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Department</FormLabel>
                    <FormControl>
                      <DynamicSelect
                        placeholder="Select department"
                        endpoint={`${process.env.NEXT_PUBLIC_API_VERSION ?? "V1"}/jobs/departments`}
                        label="title"
                        value="_id"
                        field={field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <div className="grid sm:grid-cols-2">
              <FormField
                control={form.control}
                name="country"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Country</FormLabel>
                    <FormControl>
                      <Select {...field}>
                        <SelectTrigger className="w-full">
                          <SelectValue placeholder="Select country" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectGroup>
                            {countries.map((country) => (
                              <SelectItem
                                key={country.code}
                                value={country.name}
                              >
                                {country.name}
                              </SelectItem>
                            ))}
                          </SelectGroup>
                        </SelectContent>
                      </Select>
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="city"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>City</FormLabel>
                    <FormControl>
                      <Input placeholder="e.g. Marketing" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <div className="grid sm:grid-cols-2">
              <FormField
                control={form.control}
                name="employmentType"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Employment Type</FormLabel>
                    <FormControl>
                      <Select {...field}>
                        <SelectTrigger className="w-full">
                          <SelectValue placeholder="Select country" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectGroup>
                            {JobEmploymentTypeOptions.map(
                              (type: JobEmploymentTypeOption) => (
                                <SelectItem key={type.value} value={type.value}>
                                  {type.label}
                                </SelectItem>
                              ),
                            )}
                          </SelectGroup>
                        </SelectContent>
                      </Select>
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="experienceLevel"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Experience Level</FormLabel>
                    <FormControl>
                      <Select {...field}>
                        <SelectTrigger className="w-full">
                          <SelectValue placeholder="Select country" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectGroup>
                            {JobExperienceLevelOptions.map(
                              (type: JobExperienceLevelOption) => (
                                <SelectItem key={type.value} value={type.value}>
                                  {type.label}
                                </SelectItem>
                              ),
                            )}
                          </SelectGroup>
                        </SelectContent>
                      </Select>
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <div className="grid sm:grid-cols-2">
              <FormField
                control={form.control}
                name="status"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Status</FormLabel>
                    <FormControl>
                      <Select {...field}>
                        <SelectTrigger className="w-full">
                          <SelectValue placeholder="Select status" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectGroup>
                            {JobStatusOptions.map((status: JobStatusOption) => (
                              <SelectItem
                                key={status.value}
                                value={status.value}
                              >
                                {status.label}
                              </SelectItem>
                            ))}
                          </SelectGroup>
                        </SelectContent>
                      </Select>
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="isRemote"
                render={({ field }) => (
                  <FormItem className="flex flex-row items-center space-x-3 space-y-0">
                    <FormControl>
                      <Switch
                        id="remote-job"
                        checked={field.value ?? false}
                        onCheckedChange={field.onChange}
                      />
                      <Label htmlFor="remote-job" className="ml-3">Remote</Label>
                    </FormControl>
                    <FormLabel className="mb-0">Is Remote</FormLabel>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>
          </div>
        </form>
      </Form>
    </FormDialog>
  );
}
